/* 服の種類ごとのシルエット（外部写真が使えない環境でも確実に表示・区別できる） */
const GARMENT_PATHS = {
  top: "M8.2 3 L4 5.5 2.2 10 5.4 11.6 7 9.6 7 21 17 21 17 9.6 18.6 11.6 21.8 10 20 5.5 15.8 3 C14.6 5 9.4 5 8.2 3 Z",
  outer:
    "M8 3 L3.8 5.5 2 10 5.2 11.6 6.8 9.6 6.8 21 11 21 11 8 13 8 13 21 17.2 21 17.2 9.6 18.8 11.6 22 10 20.2 5.5 16 3 13.8 6.5 12 8 10.2 6.5 Z",
  dress:
    "M8.4 3 L5 5.2 3.4 9 6 10.6 7.2 9 6.2 14 4.6 21 19.4 21 17.8 14 16.8 9 18 10.6 20.6 9 19 5.2 15.6 3 C14.4 5 9.6 5 8.4 3 Z",
  pants: "M6.5 3 L17.5 3 17.5 21 13.4 21 12 9.5 10.6 21 6.5 21 Z",
  skirt: "M7.5 4 L16.5 4 16.5 6.5 20 21 4 21 7.5 6.5 Z",
  shoes:
    "M2.5 14 C2.5 13.4 3 13 3.6 13 L8 13 11 15.5 19 17 C20.6 17.3 21.5 17.7 21.5 18.7 L21.5 19.5 C21.5 20.1 21 20.5 20.4 20.5 L3.6 20.5 C3 20.5 2.5 20.1 2.5 19.5 Z",
  bag: "M6 9 L18 9 17 20.5 7 20.5 Z",
};

function GarmentIcon({ kind = "top", size = 40, color = "rgba(70,60,65,.4)" }) {
  const d = GARMENT_PATHS[kind] || GARMENT_PATHS.top;
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none">
      <path d={d} fill={color} />
      {kind === "bag" && (
        <path
          d="M9 9 C9 5.5 15 5.5 15 9"
          stroke={color}
          strokeWidth="1.7"
          fill="none"
        />
      )}
    </svg>
  );
}

/* 服の画像。写真があれば実写を敷き、無ければ／読み込み失敗時は種類別シルエット。
   親要素は position:relative・overflow:hidden・背景にグラデを持つ前提。 */
function ItemImage({ item, icon = 44 }) {
  const [ok, setOk] = useState(true);
  if (item.photo && ok) {
    return (
      <img
        src={item.photo}
        alt={item.name || ""}
        onError={() => setOk(false)}
        style={{
          position: "absolute",
          inset: 0,
          width: "100%",
          height: "100%",
          objectFit: "cover",
        }}
      />
    );
  }
  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <GarmentIcon
        kind={item.kind}
        size={icon}
        color={item.iconOnDark ? "rgba(255,255,255,.85)" : "rgba(70,60,65,.42)"}
      />
    </div>
  );
}

/* ------------------------------------------------------------------ */
export default function App() {
  const [tab, setTab] = useState("closet");
  const [filter, setFilter] = useState("all");
  const [closet, setCloset] = useState(CLOSET); // 手持ちの服（登録で増える）
  const [selected, setSelected] = useState(null); // クローゼットで開く詳細
  const [outfitItem, setOutfitItem] = useState(null); // 私のパートナーへ渡す服
  const [todayItem, setTodayItem] = useState(null); // 「出発」して今おでかけ中の服
  const [records, setRecords] = useState([]); // 帰宅時の振り返り [{id, esteem}]
  const [showReturn, setShowReturn] = useState(false); // 帰宅通知の表示
  const [showAdd, setShowAdd] = useState(false); // 服の登録シート
  const [toast, setToast] = useState(null);

  const rescuedIds = useMemo(() => records.map((r) => r.id), [records]);

  // 救出した服のぶん、総死蔵コストは減り、今月の救出コストは増える（ループの実感）
  const totalDead = useMemo(
    () =>
      closet
        .filter((x) => !rescuedIds.includes(x.id))
        .reduce((s, x) => s + x.deadCost, 0),
    [closet, rescuedIds]
  );
  const rescuedTotal = useMemo(
    () =>
      RESCUED_THIS_MONTH +
      closet
        .filter((x) => rescuedIds.includes(x.id))
        .reduce((s, x) => s + x.deadCost, 0),
    [closet, rescuedIds]
  );

  const shown = useMemo(() => {
    if (filter === "all") return closet;
    if (filter === "star") return closet.filter((x) => x.star && x.rescuable);
    return closet.filter((x) => x.category === filter);
  }, [closet, filter]);

  // 服の登録 → クローゼットの先頭に追加
  const addItem = (item) => {
    setCloset((c) => [item, ...c]);
    setShowAdd(false);
    setTab("closet");
    showToast(`「${item.name}」をクローゼットに登録しました`);
  };

  const showToast = (msg) => {
    setToast(msg);
    window.clearTimeout(window.__t);
    window.__t = window.setTimeout(() => setToast(null), 2200);
  };

  // 「これを着ていく！」→ 私のパートナーへ服を渡す
  //  クローゼットの詳細シート・ソナーのポップアップの両方から呼ばれる
  const chooseOutfit = (item) => {
    setSelected(null);
    setOutfitItem(item);
    setTab("partner");
    showToast(`「${item.name}」を私のパートナーへ渡しました`);
  };

  // 「このコーデで出発する」→ その服を持って外出中に
  const departWith = (item) => setTodayItem(item);

  // 帰宅通知で記録 → 着た＝救出。5段階の自己肯定感を記録
  const recordReturn = (esteem) => {
    if (todayItem && !rescuedIds.includes(todayItem.id)) {
      setRecords((rs) => [...rs, { id: todayItem.id, esteem }]);
    }
    setShowReturn(false);
    setTodayItem(null);
    showToast(
      esteem >= 4
        ? "救出成功！自己肯定感を記録しました"
        : esteem <= 2
        ? "お疲れさま。着られたこと自体が一歩です"
        : "記録しました。今日も一歩前進"
    );
  };

  return (
    <div
      style={{
        minHeight: "100dvh",
        background: C.bg,
        display: "block",
        padding: 0,
        fontFamily:
          '-apple-system, "Hiragino Kaku Gothic ProN", "Noto Sans JP", system-ui, sans-serif',
      }}
    >
      {/* phone frame */}
      <div
        style={{
          width: "100%",
          maxWidth: 520,
          margin: "0 auto",
          height: "100dvh",
          background: C.bg,
          overflow: "hidden",
          position: "relative",
        }}
      >
        <style>{`
          @keyframes rc-sweep { to { transform: rotate(360deg); } }
          @keyframes rc-ring { 0%{transform:scale(.15);opacity:.55} 100%{transform:scale(1);opacity:0} }
          @keyframes rc-ping { 0%{transform:scale(1);opacity:.7} 100%{transform:scale(2.4);opacity:0} }
          @keyframes rc-pop  { from{transform:translateY(10px);opacity:0} to{transform:translateY(0);opacity:1} }
          @keyframes rc-dotin { 0%{transform:scale(0);opacity:0} 65%{transform:scale(1.15);opacity:1} 100%{transform:scale(1);opacity:1} }
          @keyframes rc-spin { to { transform: rotate(360deg); } }
          @keyframes rc-scan { 0%{transform:scale(.05);opacity:.7} 100%{transform:scale(1);opacity:0} }
        `}</style>
        {/* 実機のステータスバー領域（セーフエリア） */}

        {tab === "closet" && (
          <ClosetScreen
            shown={shown}
            filter={filter}
            setFilter={setFilter}
            totalDead={totalDead}
            rescuedTotal={rescuedTotal}
            rescuedIds={rescuedIds}
            onSelect={setSelected}
          />
        )}
        {tab === "sonar" && (
          <SonarScreen
            onChoose={chooseOutfit}
            rescuedIds={rescuedIds}
            closet={closet}
          />
        )}
        {tab === "partner" && (
          <PartnerScreen
            key={outfitItem ? outfitItem.id : "default"}
            item={outfitItem}
            showToast={showToast}
            onDepart={departWith}
            closet={closet}
          />
        )}
        {tab === "album" && (
          <AlbumScreen
            records={records}
            closet={closet}
            onNextDay={() => {
              setTab("closet");
              showToast("また明日、お気に入りを救出しよう");
            }}
          />
        )}

        {/* bottom nav */}
        <BottomNav tab={tab} setTab={setTab} />

        {/* + FAB (closet only) */}
        {tab === "closet" && (
          <button
            onClick={() => setShowAdd(true)}
            style={{
              position: "absolute",
              right: 20,
              bottom: "calc(92px + env(safe-area-inset-bottom))",
              width: 52,
              height: 52,
              borderRadius: "50%",
              border: "none",
              background: C.wine,
              color: "#fff",
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              boxShadow: "0 8px 20px rgba(124,74,84,.45)",
              zIndex: 30,
            }}
          >
            <Plus size={24} />
          </button>
        )}

        {/* おでかけ中バッジ → タップで帰宅通知（デモ） */}
        {todayItem && !showReturn && (
          <button
            onClick={() => setShowReturn(true)}
            style={{
              position: "absolute",
              left: "50%",
              transform: "translateX(-50%)",
              bottom: "calc(92px + env(safe-area-inset-bottom))",
              display: "inline-flex",
              alignItems: "center",
              gap: 7,
              border: "none",
              background: C.ink,
              color: "#fff",
              fontSize: 12.5,
              fontWeight: 700,
              padding: "10px 16px",
              borderRadius: 999,
              cursor: "pointer",
              boxShadow: "0 8px 20px rgba(0,0,0,.3)",
              zIndex: 30,
              whiteSpace: "nowrap",
            }}
          >
            <Home size={15} />
            おでかけ中：帰宅する（デモ）
          </button>
        )}

        {/* closet detail sheet */}
        {selected && (
          <DetailSheet
            item={selected}
            onClose={() => setSelected(null)}
            onChoose={() => chooseOutfit(selected)}
          />
        )}

        {/* 帰宅時クイック通知 */}
        {showReturn && todayItem && (
          <ReturnHomeOverlay item={todayItem} onRecord={recordReturn} />
        )}

        {/* 服の登録 */}
        {showAdd && (
          <RegisterSheet onClose={() => setShowAdd(false)} onSave={addItem} />
        )}

        {/* toast */}
        {toast && (
          <div
            style={{
              position: "absolute",
              left: 20,
              right: 20,
              bottom: 150,
              background: "rgba(44,42,46,.95)",
              color: "#fff",
              fontSize: 13,
              padding: "12px 16px",
              borderRadius: 14,
              textAlign: "center",
              zIndex: 40,
            }}
          >
            {toast}
          </div>
        )}
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
